﻿using APIs_BeFirst.Controllers;
using APIs_BeFirst.Models.DataBase;
using APIs_BeFirst.Models.DataMachines;
using APIs_BeFirst.Models.Response;
using Microsoft.EntityFrameworkCore;
using Newtonsoft.Json;
using Newtonsoft.Json.Linq;
using System.Data;
using System.Text.RegularExpressions;
using Microsoft.Extensions.Options;
using static APIs_BeFirst.Framework.APIs.Account;
using static APIs_BeFirst.Models.Response.AccountResponse;
using APIs_BeFirst.Service.Account;
using System.Runtime.Intrinsics.X86;
using System.Security.Cryptography.Xml;
using System.Collections.Generic;
using static APIs_BeFirst.Models.Response.QualityResponse;

namespace APIs_BeFirst.Service.Units.cs
{
    public class UnitsService : ModelBase, IUnitsService
    {

        private readonly SettingsController _settingsController;
        private readonly string JUA1_APIURL;
        private readonly string JUA2_APIURL;
        private readonly string GRA1_APIURL;
        private readonly string APIPassword;
        private readonly string APIUser;
        protected readonly ProdMesDbContext _context;
        protected readonly ProdMachinesResultsContext _contextProdMachines;
        private readonly StationController _stationController;
        private readonly string BeFirstSITE;
        private int? _facilityKey;


        public UnitsService(ProdMesDbContext context, StationController stationController, ProdMachinesResultsContext contextProdMachines, IOptions<BeFirstSettings> options) : base(context)
        {
            _context = context;
            _contextProdMachines = contextProdMachines;
            _stationController = stationController;
            //JUA1_APIURL = options.Value.APIUrl_JUA1;
            //JUA2_APIURL = options.Value.APIUrl_JUA2;
            //GRA1_APIURL = options.Value.APIUrl_GRA1;
            //APIPassword = options.Value.APIPassword;
            //APIUser = options.Value.APIUser;
            //BeFirstSITE = options.Value.BeFirstSITE;

            BeFirstSITE = Environment.GetEnvironmentVariable("BeFirst:Site"); // JUA1 JUA2 GRA1

            JUA1_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_JUA1"); // JUA1 JUA2 GRA1
            JUA2_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_JUA2"); // JUA1 JUA2 GRA1
            GRA1_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_GRA1"); // JUA1 JUA2 GRA1

            APIPassword = Environment.GetEnvironmentVariable("BeFirst:APIPassword");
            APIUser = Environment.GetEnvironmentVariable("BeFirst:APIUser");
        }
        private async Task<int> GetFacilityKey()
        {
            if (_facilityKey == null)
            {
                _facilityKey = await _context.CommonBuildings
                                    .Where(cb => Convert.ToInt32(cb.MainFacility) == 1)
                                    .Select(cb => cb.FacilityKey)
                                    .FirstOrDefaultAsync();
            }
            return _facilityKey.Value;
        }


        public async Task<UnitsCheckInResult> CheckInAsync(string SSN, int PartID, int StationID, int AreaID, string Side, int BinID, string Mode, string UserId, DateTime? CheckIn)
        {
            UnitsCheckInResult newmodel = new UnitsCheckInResult();

            newmodel.SSN = SSN;
            newmodel.SSNPanel = SSN;


            bool meetsSetup = true;

            /* GET Station SETUP */
            var response = await _stationController.SetupIDGet(StationID, "");

            if (response == null)
            {
                meetsSetup = false;
                throw new InvalidOperationException("Error trying to get SetupID");
            }
            else
            {
                StationSetupID CurrentSetup = response.Value;

                bool updateSetup = false;

                if (CurrentSetup == null)
                {
                    meetsSetup = false;
                    throw new InvalidOperationException("Error trying to get Current SetupID");
                }

                /* VALIDATE SETUP */
                if (CurrentSetup.PartID != PartID || CurrentSetup.Side != Side || CurrentSetup.BinID != BinID)
                {
                    meetsSetup = false;
                    throw new InvalidOperationException("Invalid Setup. Check Setup.");
                }
                // REGEX VALIDATION
                Regex regex = new Regex(CurrentSetup.Regex);
                Match match1 = regex.Match(SSN);

                if (Mode == "SINGLE")
                {

                }
                else if (Mode == "PANEL")
                {
                    regex = new Regex(CurrentSetup.PanelRegex);
                    match1 = regex.Match(SSN);
                }

                if (match1.Success == false)
                {
                    if (Mode == "SINGLE")
                    {
                        meetsSetup = false;
                        throw new InvalidOperationException("Invalid Format: " + CurrentSetup.RegexHumanable);
                    }
                    else if (Mode == "PANEL")
                    {
                        meetsSetup = false;
                        throw new InvalidOperationException("Invalid Format: " + CurrentSetup.PanelRegexHumanable);
                    }
                }
                else
                {

                    /* ADDTIONAL Setup */

                    bool HaveConversionBefore = false;

                    var dtHaveConversionBefore = await _context.PartOperationPackoutSubConversions
                                                .Where(p => p.PartId == CurrentSetup.PartID && p.StageId < CurrentSetup.StageID)
                                                .Select(p => p.StageId)
                                                .ToListAsync();

                    if (dtHaveConversionBefore.Count() > 0)
                    {
                        HaveConversionBefore = true;
                    }


                    var dtAreastoReview = await _context.PartOperationReviewOperations
                                            .Where(p => p.PartId == CurrentSetup.PartID && p.CurrentAreaId == CurrentSetup.AreaID && p.CurrentSide == CurrentSetup.Side)
                                            .Join(_context.PartOperationAreas,
                                                    p => p.PreviousAreaId,
                                                    a => a.AreaId,
                                                    (p, a) => new
                                                    {
                                                        AreaID = p.PreviousAreaId,
                                                        Area = a.Area,
                                                        Previous_Date = p.PreviousDate,
                                                        Side = p.PreviousSide
                                                    })
                                            .ToListAsync();

                    string Check_Other_Site = await _context.PartInterplants
                                            .Where(p => p.PARTID == CurrentSetup.PartID)
                                            .Select(p => p.SITE)
                                            .FirstOrDefaultAsync() ?? "";

                    var dtAreasToReveiwAOI = await _context.PartOperationSearchaois
                                                .Where(p => p.AreaId == CurrentSetup.AreaID && p.Side == CurrentSetup.Side && p.PartId == CurrentSetup.PartID)
                                                .Join(_context.PartOperationAreas,
                                                        p => p.SearchAreaId,
                                                        a => a.AreaId,
                                                        (p, a) => new
                                                        {
                                                            AreaID = p.SearchAreaId,
                                                            Area = a.Area,
                                                            Side = p.SearchSide
                                                        })
                                                .ToListAsync();



                    int allowFailuresInArea = await _context.PartOperationAreasFailuresAlloweds
                                                .Where(p => p.AreaId == CurrentSetup.AreaID)
                                                .Select(p => p.FailuresAllowed)
                                                .FirstOrDefaultAsync();


                    var dtPrintSubConversion = await _context.PartOperationPackoutSubConversions
                                                        .Where(p => p.PartId == CurrentSetup.PartID)
                                                        .Select(p => p.PartId)
                                                        .ToListAsync();

                    var dtIgnoreStage = await _context.CsTblPartnumberSkipstages
                                                .Where(cs => cs.StageId == CurrentSetup.StageID && cs.PartId == CurrentSetup.PartID)
                                                    .Join(_context.PdTblRutes,
                                                            cs => new { StageId = (int)cs.StageId, PartId = (int)cs.PartId },  // Convertimos los valores explícitamente a int
                                                            pd => new { StageId = (int)pd.Stage, PartId = (int)pd.PartId },
                                                            (cs, pd) => new
                                                            {
                                                                AutoId = cs.AutoId,
                                                                PartId = cs.PartId,
                                                                StageId = cs.StageId,
                                                                FacilityKey = cs.FacilityKey,
                                                                AreaID = pd.AreaId,
                                                                Side = pd.Side
                                                            }
                                                        )
                                                        .ToListAsync();


                    var dtMaxScans = await _context.PartOperationAreasMaxscans
                                                .Select(p => new
                                                {
                                                    AutoID = p.AutoId,
                                                    AreaID = p.AreaId,
                                                    Side = p.Side,
                                                    Quantity = p.Quantity
                                                })
                                                .ToListAsync();

                    var dtMaxScansByPart = await _context.PartOperationMaxscans
                                                .Select(p => new
                                                {
                                                    AutoID = p.AutoId,
                                                    AreaID = p.AreaId,
                                                    Side = p.Side,
                                                    Quantity = p.Quantity,
                                                    PartID = p.PartId
                                                })
                                                .ToListAsync();


                    /* Check each SSN */

                    var unitsInPanel = new List<ChildsInParent>();

                    if (Mode == "SINGLE")
                    {
                        ChildsInParent newUnit = new ChildsInParent();

                        newUnit.Parent = "NA";
                        newUnit.Child = SSN;

                        newUnit.DefectCode = 0;
                        newUnit.IsGood = true;
                        newUnit.IsRework = false;

                        newUnit.IsFromPanel = false;

                        newUnit.ArrayPosition = 1;

                        unitsInPanel.Add(newUnit);
                    }
                    else if (Mode == "PANEL")
                    {

                        int QuantityUnitsInPanel = 1;



                        var dtPanelQuantity = await _context.Parts
                                                    .Where(p => p.PartId == PartID)
                                                    .Select(p => p.PiecesByPanel)
                                                    .FirstOrDefaultAsync();


                        if (dtPanelQuantity != null)
                        {
                            QuantityUnitsInPanel = (int)dtPanelQuantity;
                        }


                        string PanelSSN = SSN;


                        var dtParent = await _context.PartUnitsArrays
                                                .Where(p => p.Child == SSN)
                                                .Select(p => p.Parente)
                                                .FirstOrDefaultAsync();


                        if (dtParent != null)
                        {
                            PanelSSN = dtParent;
                            newmodel.SSNPanel = PanelSSN;

                            // TODO: CheckIN - Validate SSNPanel Regex
                        }

                        // TODO: CheckIN - Valdiate SSNPnael Stage

                        var dtChilds = await _context.PartUnitsArrays
                                                    .Where(p => p.Parente == PanelSSN)
