                                    .Select(p => p.AutoId)
                                    .ToListAsync();


            if (dtCheckIn.Count > 0)
            {

                bool IsGood = false;
                string Comments = "";

                if (result == "PASS")
                {
                    IsGood = true;
                }
                else
                {
                    Comments = failureDescription;
                }

                int ssnIndex = 1;
