        public async Task<List<UnitsHistory>> GetUnitResultHistorySiteAsync(string Site, string SSN, string Area = "", string Side = "", string PartNumber = "", string BinCode = "")
        {
            try
            {
                // SITES AVAILABLES
                var accounts = new Dictionary<string, APIs_BeFirst.Framework.APIs.Account>
                {
                    { "JUA1", new(JUA1_APIURL, APIUser, APIPassword) },
                    { "JUA2", new(JUA2_APIURL, APIUser, APIPassword) },
                    { "GRA1", new(GRA1_APIURL, APIUser, APIPassword) },
                    { "GRP1", new(GRA1_APIURL, APIUser, APIPassword) }
                };

                // Validación de site
                if (!accounts.TryGetValue(Site.ToUpper(), out var account))
                    throw new ArgumentException($"Invalid site: {Site}");

                // Construcción de parámetros
                var parameters = new List<URLInput>
                    {
                        new() { Name = "SSN", Value = SSN },
                        new() { Name = "Area", Value = Area },
                        new() { Name = "Side", Value = Side },
                        new() { Name = "PartNumber", Value = PartNumber },
                        new() { Name = "BinCode", Value = BinCode }
                    }.Where(p => !string.IsNullOrEmpty(p.Value)).ToList();

                // Llamada a la API
                var response = account.API_Call("/Units/GetUnitResultHistory", "GET", parameters);

                // Verificación de la respuesta
                if (response.ResponseCode != 200 || string.IsNullOrWhiteSpace(response.Response))
                    throw new ApplicationException($"API call failed for site {Site}, ResponseCode: {response.ResponseCode}");

                // Deserialización segura con validación de respuesta
                var result = JsonConvert.DeserializeObject<List<UnitsHistory>>(response.Response);
                return result ?? new List<UnitsHistory>();
            }
            catch (Exception ex)
            {
                // Lanzar la excepción al controlador o manejarla
                throw new ApplicationException($"An error occurred while fetching unit history: {ex.Message}", ex);
            }
        }

        public async Task<ICCOunter> GetNextICCounterAsync(string Part_No)
        {

            var newModel = new ICCOunter();

            if (Part_No.Length > 0)
            {

                var dtDetails = _context.PartOperationFunctionGetUniqueIcIds
                                        .Where(p => p.PartNo == Part_No)
                                        .Select(p => new
                                        {
                                            p.Autoid,
                                            p.PartNo,
                                            p.Counter,
                                            p.Type,
                                            p.UpdateDate,
                                        })
                                        .ToList();

                newModel.PartNo = Part_No;


                if (dtDetails.Count() > 0)
                {
                    var tempCounter = dtDetails.FirstOrDefault().Counter;
                    var tempTYPE = dtDetails.FirstOrDefault().Type;

                    if (tempTYPE == "HEX-10") // Hexadecimal 10 digits
                    {
                        string hexValue = tempCounter; // Example hex value
                        int decimalValue = Convert.ToInt32(hexValue, 16);
                        int result = decimalValue + 1;
                        string newHexValue = result.ToString("X10");

                        var record = _context.PartOperationFunctionGetUniqueIcIds
                                                .FirstOrDefault(p => p.PartNo == Part_No);

                        if (record != null)
                        {
                            record.Counter = newHexValue;
                            record.UpdateDate = DateTime.Now;

                            _context.SaveChanges();
                        }


                        var dtComparasion = _context.PartOperationFunctionGetUniqueIcIds
                                                .Where(p => p.PartNo == Part_No)
                                                .Select(p => new
                                                {
                                                    p.Autoid,
                                                    p.PartNo,
                                                    p.Counter,
                                                    p.Type,
                                                    p.UpdateDate
                                                })
                                                .ToList();

                        if (dtComparasion.Count() > 0)
                        {
                            var valtempCounter = dtComparasion.FirstOrDefault().Counter.ToString();

                            if (valtempCounter == newHexValue)
                            {
                                newModel.Counter = tempCounter;
                                newModel.Type = tempTYPE;
                            }
                        }
                    }
                }
            }

            return newModel;

        }

        public async Task<List<ChildsInParent>> ArrayGetChildsAsync(string ChildOrParent, int? PartID = null, int? AreaID = null, string? Side = null)
        {
            List<ChildsInParent> unitsInPanel = new List<ChildsInParent>();

            string PanelSSN = ChildOrParent;

            var dtParent = _context.PartUnitsArrays
                .Where(p => p.Child == ChildOrParent)
                .Select(p => p.Parente)
                .ToList();


            if (dtParent.Count() > 0)
            {
                PanelSSN = dtParent.FirstOrDefault();
            }

            // Use provided parameters or defaults
            // If PartID is -1, the LEFT JOIN will return no remapping and original order is used
            int effectivePartID = PartID ?? -1;
            int effectiveAreaID = AreaID ?? 0;
            string effectiveSide = Side ?? "A";

            // TODO: CheckIN - Valdiate SSNPnael Stage

            // Query with remapping support (LEFT JOIN - returns original data if no remap exists)
            var query = from array in _context.PartUnitsArrays
                        where array.Parente == PanelSSN
                        join remap in _context.PartOperationSerializationArrayIndexRemaps
                            on new { PartID = (int?)effectivePartID, AreaID = effectiveAreaID, Side = effectiveSide, OriginalIndex = array.SortNo }
                            equals new { PartID = (int?)remap.PartId, AreaID = remap.AreaId, Side = remap.Side, OriginalIndex = (int?)remap.OriginalIndex }
                            into remapGroup
                        from remap in remapGroup.DefaultIfEmpty()
                        select new
                        {
                            array.Child,
                            array.SortNo,
                            RemappedIndex = remap != null ? remap.RemappedIndex : array.SortNo,
                            array.AutoId
                        };

            // Order by remapped index (or original if no remap exists)
            var dtChilds = query
                .OrderBy(p => p.RemappedIndex)
                .ThenBy(p => p.AutoId)
                .AsEnumerable()
                .Select((p, index) => new
                {
                    p.Child,
                    Sort_No = index + 1,
                    p.SortNo,
                    p.RemappedIndex
                })
                .ToList();


            if (dtChilds.Count() == 0)
            {
                throw new InvalidOperationException("No records for this unit in Parents/Arrays.");
            }
            else
            {
                foreach (var rowChild in dtChilds)
                {
                    ChildsInParent newUnit = new ChildsInParent();

                    newUnit.Parent = PanelSSN;
                    newUnit.Child = rowChild.Child.ToString();

                    newUnit.DefectCode = 0;
                    newUnit.IsGood = false;
                    newUnit.IsRework = false;

                    newUnit.IsFromPanel = true;

                    newUnit.ArrayPosition = int.Parse(rowChild.Sort_No.ToString());

                    unitsInPanel.Add(newUnit);
                }
            }

            return unitsInPanel;
        }


