            var dt_merging = await _context.PartParentChilds
                                        .Join(_context.Parts,
                                                child => child.PartId,
                                                parentNum => parentNum.PartId,
                                                (child, parentNum) => new { child, parentNum })
                                        .Join(_context.Parts,
                                                cp => cp.child.ChildPartId,
                                                childNum => childNum.PartId,
                                                (cp, childNum) => new { cp.child, cp.parentNum, childNum })
                                        .Join(_context.PartParents,
                                                cp2 => new { cp2.child.GroupId, cp2.child.PartId },
                                                parent => new { parent.GroupId, parent.PartId },
                                                (cp2, parent) => new { cp2.child, cp2.parentNum, cp2.childNum, parent })
                                        .Join(_context.PartBins,
                                                cp3 => new { PartID = (int?)cp3.child.ChildPartId, BinID = (int?)cp3.child.ChildPartBinId },
                                                bin => new { PartID = (int?)bin.PartId, BinID = (int?)bin.BinId },
