                                               .FirstOrDefaultAsync();

                        if (childStage >= 0)
                        {
                            var selectBines = dt_ToMerge.Where(item => item.Child_PartID == Convert.ToString(getPartID));

                            bool pass = false;

                            foreach (var values in selectBines)
                            {
                                Regex regex1 = new Regex(values.Child_PartFormat.ToString());
                                if (regex1.Match(child).Success)
                                {
                                    pass = true;

                                    bool prevop = false;

                                    // Validate Stage of childs | Ignore for now

