                        tracking => tracking.AreaId,
                        area => area.AreaId,
                        (tracking, area) => new { tracking, area })
                    .Join(_context.Parts,
                        combined => combined.tracking.PartId,
                        PNPartID => PNPartID.PartId,
                        (combined, PNPartID) => new { combined.tracking, combined.area, PNPartID })
                    .GroupJoin(_context.PartBins,
                    combined2 => new { PartID = (int?)combined2.tracking.PartId, BinID = (int?)combined2.tracking.GroupMls },
                    bin => new { PartID = (int?)bin.PartId, BinID = (int?)bin.BinId },
                    (combined2, bins) => new { combined2.tracking, combined2.area, combined2.PNPartID, bins })
                    .SelectMany(
                    combined2 => combined2.bins.DefaultIfEmpty(),
                    (combined2, bin) => new
                    {
                        tracking = combined2.tracking,
                        area = combined2.area,
                        PNPartID = combined2.PNPartID,
                        BinCode = bin != null ? bin.BinName : ""
                    })
                    .Where(x => x.tracking.Ssnpanel == SSNPanel &&
                    (AreaID == 0 || x.tracking.AreaId == AreaID) &&
                    (string.IsNullOrEmpty(Side) || x.tracking.JobSide == Side) &&
                    (PartID == 0 || x.tracking.PartId == PartID) &&
                    (BinID == 0 || x.tracking.GroupMls == BinID)
                    )
                    .OrderByDescending(x => x.tracking.TrnDate)
                    .Select(x => new
                    {
                        IsGood = x.tracking.IsGood,
                        PartID = x.tracking.PartId,
                        Side = x.tracking.JobSide,
                        SSN = x.tracking.Ssn,
                        AreaID = x.tracking.AreaId,
                        Area = x.area.Area,
                        PartNumber = x.PNPartID.PartNumber,
                        TrnDate = x.tracking.TrnDate,
                        BinCode = x.BinCode
                    })
                    .ToListAsync();

                var newmodel = new List<UnitsHistory>();

                foreach (var rowHistory in dtDetails)
                {
                    UnitsHistory historyEvent = new UnitsHistory
                    {
                        SSN = rowHistory.SSN,
                        Area = rowHistory.Area,
                        Side = rowHistory.Side,
                        IsGood = rowHistory.IsGood ?? false,
                        TrnDate = rowHistory.TrnDate ?? DateTime.MinValue,
                        PartNumber = rowHistory.PartNumber,
                        Site = BeFirstSITE,
                        BinCode = rowHistory.BinCode
                    };

                    newmodel.Add(historyEvent);
                }
                return newmodel;
            }
            return null;

        }

        public async Task<UnitsCheckOutResult> CheckOutAsync(string SSN, string SSNPanel, string result, int partID, int stationID, int areaID, string side, int binID, int stageID, int setupId = 0, int ssnQty = 1, int jobTypeID = -1, int jobID = -1, int jobNumber = -1, int nestID = 1, int toolID_1 = 0, int toolID_2 = 0, string failureDescription = "", string unitAlternate = "", string mode = "SINGLE", string userId = "", DateTime? trnDate = null)
        {
            var newmodel = new UnitsCheckOutResult();

            newmodel.SSN = SSN;
            newmodel.CheckOut = false;

            if (SSN.Length == 0)
            {
                throw new ArgumentException("Select a valid SSN.");
            }

            if (mode != "SINGLE" && mode != "PANEL")
            {
