        public async Task<UnitsCheckInResult> AOIPanelGettAsync(string SSN, int AreaID, string Side)
        {

            UnitsCheckInResult newModel = new UnitsCheckInResult();

            string SSNPANEL = SSN;

            bool allUnitsOk = true;

            var dtParente = await _context.PartUnitsArrays
                            .Where(p => p.Child == SSN || p.Parente == SSN)
                            .Select(p => p.Parente)
                            .ToListAsync();


            if (dtParente.Count() > 0)
            {
                SSNPANEL = Convert.ToString(dtParente[0]) ?? "";

                var dtChilds = _context.PartUnitsArrays
                                            .Where(p => p.Parente == SSNPANEL)
                                            .OrderBy(p => p.SortNo)
                                            .ThenBy(p => p.AutoId)
                                            .AsEnumerable()
                                            .Select((p, index) => new
                                            {
                                                p.Child,
                                                Sort_No = index + 1  // Simula ROW_NUMBER() empezando desde 1
                                            })
                                            .ToList();

                foreach (var rowChild in dtChilds)
                {
                    UnitsCheckIn newUnit = new UnitsCheckIn();
                    newUnit.SSN = Convert.ToString(rowChild.Child.ToString()) ?? "";

                    bool recordIsOK = false;

                    var resultAOI = await AOIGetAsync(newUnit.SSN, AreaID, Side);

                    if (resultAOI == null)
                    {
                        recordIsOK = false;
                        allUnitsOk = false;
                    }
                    else
                    {
                        ResponseUnits unitAOI = resultAOI;

                        if (unitAOI.IsGood)
                        {
                            recordIsOK = true;
                        }
                        else
                        {
                            recordIsOK = false;
                            allUnitsOk = false;
                        }
                    }

                    newUnit.SSNPanel = SSNPANEL;
                    newUnit.CheckIn = recordIsOK;
                    newUnit.ArrayPosition = int.Parse(rowChild.Sort_No.ToString());
                    newUnit.Message = "";
                    newModel.UnitsCheckIn.Add(newUnit);
                }

                newModel.IsPanel = true;
                newModel.CheckIn = allUnitsOk;
            }
            else
            {
                newModel.SSNPanel = SSN;
                newModel.SSNPanel = "";
                newModel.IsPanel = false;
                newModel.CheckIn = false;
                newModel.Message = "Unit not merged";
            }

            return newModel;

        }

        public async Task<ResponseUnits> GetAOIResultAsync(string SSN, int AreaID, string Side)
        {

            var newModel = new ResponseUnits();


            var dtDetails = await _contextProdMachines.MachinesExtractorAoiData
                                            .Where(m => m.Sn == SSN && m.AreaId == AreaID && m.Side == Side)
                                            .OrderByDescending(m => m.Trndate)
                                            .Select(m => new { m.IsGood, m.PartId })
                                            .FirstOrDefaultAsync();


            newModel.SSN = SSN;
            newModel.Area = await _context.PartOperationAreas
                                        .Where(a => a.AreaId == AreaID)
                                        .Select(a => a.Area)
                                        .FirstOrDefaultAsync();

            newModel.IsGood = false;
            newModel.Side = Side;
            newModel.PartID = 0;

            if (dtDetails != null)
            {
                newModel.IsGood = bool.Parse(dtDetails.IsGood.ToString());
                newModel.PartID = dtDetails.PartId;
            }

            return newModel;


        }


        //// CHECK IF THE SSN IS ON THE RABBBT LIST
        public async Task<List<Rabbits>> CheckRabbitListAsync(string SSN)
        {
            var rabbitList = await _context.QualityRabbits
                .Where(x => x.Ssn == SSN)
                .Join(_context.Parts,
                QR => QR.PartId,
                PN => PN.PartId,
                (QR, PN) => new { QR, PN })
                .Join(_context.PartOperationAreas,
                QRA => QRA.QR.AreaId,
                POA => POA.AreaId,
                (QRA, POA) => new Rabbits
                {
                    PartId = QRA.QR.PartId,
                    AreaId = QRA.QR.AreaId,
                    PartNumber = QRA.PN.PartNumber,
                    Ssn = QRA.QR.Ssn,
                    Area = POA.Area,
                    IsActive = QRA.QR.IsActive,
                    Side = QRA.QR.Side,
                    Description = QRA.QR.Description,
                    ErrorNo = QRA.QR.ErrorNo,
                    CalibrationDate = QRA.QR.CalibrationDate,
                    CalibrationExpiration = QRA.QR.CalibrationDate
                })
                .ToListAsync();

            if (rabbitList.Any())
            {
                return rabbitList;
            }
            else
            {
                throw new InvalidOperationException("The SSN isn't a rabbit.");
            }

        }

        public async Task<bool> CheckCorrectArray(string Child, int Sort_No)
        {
            var checkchild = await _context.PartUnitsArrays
                .AsNoTracking()
                .Where(x => x.Child == Child)
                .Select(x => x.Child)
                .FirstOrDefaultAsync();

            if(checkchild == null)
            {
                throw new InvalidOperationException("Child not found.");
            }

            bool result = await _context.PartUnitsArrays.AnyAsync(x => x.Child == Child && x.SortNo == Sort_No);

            return result;
        }

        // ================================================================================
        // LOCKED UNITS OPERATIONS (EF Core)
        // ================================================================================

        public async Task<List<PartUnitsLocked>> GetLockedUnitsAsync(string sn)
        {
            return await _context.PartUnitsLockeds
                .Where(x => x.Sn == sn)
                .ToListAsync();
        }

        public async Task<bool> AddLockedUnitAsync(string partNo, string sn, int controlId, string comments)
        {
            try
            {
                var lockedUnit = new PartUnitsLocked
                {
                    PartNo = partNo,
                    Sn = sn,
                    TrnDate = DateTime.Now,
                    ControlId = controlId,
                    Comments = comments,
                    Scrap = false,
                    ScrapReason = ""
                };

                await _context.PartUnitsLockeds.AddAsync(lockedUnit);
                await _context.SaveChangesAsync();
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> DeleteLockedUnitsAsync(string sn, string commentPattern)
        {
            try
            {
                var unitsToDelete = await _context.PartUnitsLockeds
                    .Where(x => x.Sn == sn && EF.Functions.Like(x.Comments, commentPattern))
                    .ToListAsync();

                if (unitsToDelete.Any())
                {
                    _context.PartUnitsLockeds.RemoveRange(unitsToDelete);
                    await _context.SaveChangesAsync();
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        // ================================================================================
        // PARENT-CHILD ARRAY OPERATIONS (EF Core)
        // ================================================================================

        public async Task<bool> AddArrayRelationshipAsync(string parent, string child, int sortNo)
        {
            try
            {
                var relationship = new PartUnitsArray
                {
                    Parente = parent,
                    Child = child,
                    TrnDate = DateTime.Now,
                    SortNo = sortNo
                };

                await _context.PartUnitsArrays.AddAsync(relationship);
                await _context.SaveChangesAsync();
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> DeleteArrayRelationshipAsync(string child)
        {
            try
            {
                var relationshipsToDelete = await _context.PartUnitsArrays
                    .Where(x => x.Child == child)
                    .ToListAsync();

                if (relationshipsToDelete.Any())
                {
                    _context.PartUnitsArrays.RemoveRange(relationshipsToDelete);
                    await _context.SaveChangesAsync();
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> CheckArrayRelationshipExistsAsync(string child)
        {
            return await _context.PartUnitsArrays.AnyAsync(x => x.Child == child);
        }
    }
}

