        public UnitsService(ProdMesDbContext context, StationController stationController, ProdMachinesResultsContext contextProdMachines, IOptions<BeFirstSettings> options) : base(context)
        {
            _context = context;
            _contextProdMachines = contextProdMachines;
            _stationController = stationController;
            //JUA1_APIURL = options.Value.APIUrl_JUA1;
