            JUA1_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_JUA1"); // JUA1 JUA2 GRA1
            JUA2_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_JUA2"); // JUA1 JUA2 GRA1
            GRA1_APIURL = Environment.GetEnvironmentVariable("BeFirst:APIUrl_GRA1"); // JUA1 JUA2 GRA1

            APIPassword = Environment.GetEnvironmentVariable("BeFirst:APIPassword");
