                                                                        .Where(p => p.Ssn == ssnChild || p.Ssn == tempn_conversion)
                                                                        .Select(p => new { p.AutoId, p.Ssn, p.TrnDate })
                                                                        .ToListAsync();


                                        if (dtPrinted.Count() > 0)
                                        {
                                            insertTracking = false;
                                            messageRework++;
                                            messageerror = "Unit already printed, call QA to delete it.";
                                        }
                                    }
                                }

                                if (insertTracking == false)
                                {
                                    UnitsCheckIn newUnit = new UnitsCheckIn();
                                    newUnit.SSN = ssnChild;
                                    newUnit.SSNPanel = newmodel.SSNPanel;
                                    newUnit.CheckIn = false;
                                    newUnit.Message = messageerror;
                                    newUnit.ArrayPosition = ArrayPosition;
                                    newmodel.UnitsCheckIn.Add(newUnit);
                                }
                                else
                                {

                                    int unitStageID = 0;

                                    if (useAPIS != null && useAPIS == "1")
                                    {
                                        if (History.Count > 0)
                                        {

                                            var result = await _context.PdTblRutes
                                                .Where(x => x.PartId == PartID && x.Side == History[0].Side)
                                                .Join(
                                                    _context.PartOperationAreas.Where(x => x.Area == History[0].Area),
                                                    ruta => ruta.AreaId,  // Se pasa el AreaId directamente
                                                    area => area.AreaId,  // Se pasa el AreaId directamente
                                                    (ruta, areas) => new { ruta, areas }
                                                )
                                                .FirstOrDefaultAsync();

                                            if (result?.ruta.Stage.HasValue == true)
                                            {
                                                int stageID = result?.ruta.Stage.HasValue == true
                                                                ? (result.ruta.Stage < 0 ? -99 : result.ruta.Stage.Value)
                                                                : -99;
                                                unitStageID = stageID;

                                                if (History[0].IsGood == false)
                                                {
                                                    unitStageID = -Math.Abs(unitStageID);
                                                }
                                            }
                                            else
                                            {


                                            }
                                        }
                                    }
                                    else
                                    {

                                        // GET LAST STAGEID
                                        if (unitStageID == 0)
                                        {
                                            if (HaveConversionBefore)
                                            {
                                                var result = await _context.PdTblUnitsWips
                                                                    .Where(w => (w.Ssn == ssnChild || w.Ssn == tempn_conversion) && w.PartId == PartID)
                                                                    .GroupJoin(
                                                                        _context.PdTblRutes,
                                                                        wip => new { wip.PartId, JobSide = wip.JobSide, StatusAreaId = wip.StatusAreaId },
                                                                        ruta => new { ruta.PartId, JobSide = ruta.Side, StatusAreaId = ruta.AreaId },
                                                                        (wip, rutas) => new { wip, rutas }
                                                                    )
                                                                    .SelectMany(
                                                                        x => x.rutas.DefaultIfEmpty(),
                                                                        (x, ruta) => new
                                                                        {
                                                                            StageID = (ruta.Stage != null && ruta.Stage < 0) ? -1 : (ruta.Stage != null ? ruta.Stage : -1)
                                                                        }
                                                                    )
                                                                    .FirstOrDefaultAsync();

                                                unitStageID = result?.StageID ?? -1;

                                            }
                                            else
                                            {
                                                var result = await _context.PdTblUnitsWips
                                                                    .Where(w => w.Ssn == ssnChild && w.PartId == PartID)
                                                                    .GroupJoin(
                                                                        _context.PdTblRutes,
                                                                        wip => new { wip.PartId, JobSide = wip.JobSide, StatusAreaId = wip.StatusAreaId },
                                                                        ruta => new { ruta.PartId, JobSide = ruta.Side, StatusAreaId = ruta.AreaId },
                                                                        (wip, rutas) => new { wip, rutas }
                                                                    )
                                                                    .SelectMany(
                                                                        x => x.rutas.DefaultIfEmpty(),
                                                                        (x, ruta) => new
                                                                        {
                                                                            StageID = (ruta.Stage != null && ruta.Stage < 0) ? -1 : (ruta.Stage != null ? ruta.Stage : -1)
                                                                        }
                                                                    )
                                                                    .FirstOrDefaultAsync();

                                                unitStageID = result?.StageID ?? -1;

                                            }
                                        }
                                    }



                                    bool hasCorrect = false;

                                    // 7 - IS NEW and Stage is 1.
                                    if (hasCorrect == false && CurrentSetup.StageID == 1 && unitStageID == 0)
                                    {
                                        hasCorrect = true;
                                    }

                                    // 8 - COME FROM PREVIOUS STAGE OR IS NEW (IF LAST RECORD IN PREVOUS OP WAS OK)
                                    if (hasCorrect == false && unitStageID == CurrentSetup.StageID - 1)
                                    {
                                        if (useAPIS != null && useAPIS == "1")
                                        {
                                            hasCorrect = true;
                                        }
                                        else
                                        {
                                            hasCorrect = true;
                                        }
                                    }

                                    // 9 - COME FROM CURRENT OR BEST OPERATION
                                    if (hasCorrect == false && unitStageID >= CurrentSetup.StageID)
                                    {
                                        hasCorrect = true;
                                    }

                                    // 10 - IS BAD BUT SAME OPERATION AND IS ALLOWED TO CORRECT ACTION
                                    if (hasCorrect == false && unitStageID == CurrentSetup.StageID)
                                    {
                                        hasCorrect = true;
                                    }

                                    // 11 - IS RMA
                                    if (hasCorrect == false && CurrentSetup.Area == "RMA") // RMA OPERATION
                                    {
                                        hasCorrect = true;
                                    }

                                    // 12 - IS Quality Inpsection
                                    if (hasCorrect == false && CurrentSetup.Area == "Quality Inspection (No Plex)") // RMA OPERATION
                                    {
                                        hasCorrect = true;
                                    }

                                    //// 13 - IS MERGED BEFORE PROCESS (NO HISTORY)
                                    //if (hasCorrect == false && unitStageID == 0) // RMA OPERATION
                                    //{
                                    //    hasCorrect = true;
                                    //}

                                    // 14 - IGNORE STAGES
                                    if (hasCorrect == false && unitStageID == 0 && (dtIgnoreStage.Count() > 0)) // RMA OPERATION
                                    {
                                        hasCorrect = true;
                                    }

                                    if (hasCorrect = false)
                                    {
                                        UnitsCheckIn newUnit = new UnitsCheckIn();
                                        newUnit.SSN = ssnChild;
                                        newUnit.SSNPanel = newmodel.SSNPanel;
                                        newUnit.CheckIn = false;
                                        newUnit.ArrayPosition = ArrayPosition;
                                        newUnit.Message = "Not meet any requirement.";
                                        newmodel.UnitsCheckIn.Add(newUnit);
                                    }
                                    else
                                    {
                                        unitsOk++;

                                        UnitsCheckIn newUnit = new UnitsCheckIn();
                                        newUnit.SSN = ssnChild;
                                        newUnit.SSNPanel = newmodel.SSNPanel;
                                        newUnit.CheckIn = true;
                                        newUnit.ArrayPosition = ArrayPosition;
                                        newmodel.UnitsCheckIn.Add(newUnit);



                                        var result = new PartUnitsCheckin
                                        {
                                            PartId = PartID,
                                            Side = Side ?? "",
                                            BinId = BinID,
                                            StationId = StationID,
                                            AreaId = AreaID,
                                            Ssn = SSN ?? "",
                                            Ssnpanel = newmodel.SSNPanel ?? "",
                                            CheckIn = DateTime.Now, // Equivalente a GETDATE()
                                            CheckOut = null,
                                            UserId = UserId ?? ""
                                        };

                                        _context.PartUnitsCheckins.Add(result);
                                        await _context.SaveChangesAsync();

                                    }

                                }
                            }
                            else
                            {
                                messageInvalidFormat++;

                                UnitsCheckIn newUnit = new UnitsCheckIn();
                                newUnit.SSN = ssnChild;
                                newUnit.SSNPanel = newmodel.SSNPanel;
                                newUnit.CheckIn = false;
                                newUnit.ArrayPosition = ArrayPosition;
                                newUnit.Message = "Invalid Format";
                                newmodel.UnitsCheckIn.Add(newUnit);
                            }
                        }

                        if (unitsOk > 0)
                        {
                            newmodel.CheckIn = true;
                        }
                        else
                        {
                            newmodel.CheckIn = false;
                        }

                        if (messageInvalidFormat > 0)
                        {
                            newmodel.Message = newmodel.Message + "Invalid format for " + messageInvalidFormat + " units. ";
                        }

                        if (messageInvalidArea > 0)
                        {
                            newmodel.Message = newmodel.Message + "Invalid area for " + messageInvalidArea + " units. ";
                        }

                        if (messageMissingAOI > 0)
                        {
                            newmodel.Message = newmodel.Message + "Missing AOI inspection for " + messageMissingAOI + " units. ";
                        }

                        if (messageRework > 0)
                        {
                            newmodel.Message = newmodel.Message + "Units in rework for " + messageRework + " units. ";
                        }
                    }
                }

            }


            return newmodel;
        }

