        public async Task<bool> CheckOutParametrizedCollectionAsync(string SSN, string Result, int PartID, int StationID, int AreaID, string Side, DateTime TrnDate, string NestID, string Unit_Alternate, string testCollection, int UnitIndex = 0)
        {
