            if (Result == "PASS")
            {
                IsGood = true;
            }

            if (Unit_Alternate == "")
            {
                Unit_Alternate = SSN;
            }

            // Create string array for every component
            string[] components = testCollection.Split('/');
            var newRecords = new List<PartUnitsParametrizeddatum>();

            foreach (string component in components)
            {
                string TestStep = "";
                string Value = "";
                string Min_Value = "";
                string Max_Value = "";
                string Nom_Value = "";

                // String into an array of substrings using semicolon
                // Go through each element of the array and replace null values with empty strings
                // And Convert the modified collection into a new array of strings
                string[] testValue = component.Split(';').Select(v => v ?? "").ToArray();


                // Insert the values of the collection to the test values
                TestStep = testValue[0].Trim();
                Value = testValue[1].Trim();
                Min_Value = testValue[2].Trim();
                Max_Value = testValue[3].Trim();
                Nom_Value = testValue[4].Trim();

                // Se asume que tienes una entidad PartUnitsCheckIn que mapea a la tabla [Part_Units_CheckIn]
                var newRecord = new PartUnitsParametrizeddatum
                {
                    PartId = PartID,                          // @PartID
                    Ssn = SSN ?? "",                          // @SSN
                    IsGood = IsGood,                          // @IsGood
                    UnitIndex = UnitIndex,                    // @UnitIndex
                    StationId = StationID,                    // @StationID
                    AreaId = AreaID,                          // @AreaID
                    Side = Side ?? "",                        // @Side
                    TrnDate = TrnDate,                        // @TrnDate
                    NestId = NestID ?? "",                     // @NestID
                    WrtDate = DateTime.Now,                   // GETDATE()
                    UnitAlternate = Unit_Alternate ?? "",    // @Unit_Alternate
                    TestStep = TestStep ?? "",                // @TestStep
                    Value = Value ?? "",                      // @Value
                    MinValue = Min_Value ?? "",              // @Min_Value
                    MaxValue = Max_Value ?? "",              // @Max_Value
                    NomValue = Nom_Value ?? ""               // @Nom_Value
                };

                newRecords.Add(newRecord);
            }

            if (newRecords.Any())
            {
                _context.PartUnitsParametrizeddata.AddRange(newRecords);
                int insertedRows = await _context.SaveChangesAsync();
                newModel = insertedRows > 0;
            }

            return newModel;

        }

