                            //DataTable  = new DataTable();
                            //dtChilds.Columns.Add("Child_SSN", typeof(string));

                            if (rowItem.Child_SSN.ToString().Contains(";"))
                            {
                                string[] splitItems = rowItem.Child_SSN.ToString().Split(";");
                                foreach (string subChild in splitItems)
                                {
                                    dtChilds.Add(new MergeItem { Child_SSN = subChild });
                                }
                            }
                            else
                            {
                                dtChilds.Add(new MergeItem { Child_SSN = rowItem.Child_SSN.ToString() });
                            }

                            foreach (var childss in dtChilds)
                            {
                                var newLinkage = new PartUnitsLinkage
                                {
                                    PartId = int.Parse(rowItem.PartID.ToString()),
                                    GroupId = int.Parse(rowItem.GroupID.ToString()),
                                    Ssn = SSN,
                                    ChildPartId = int.Parse(rowItem.Child_PartID.ToString()),
                                    ChildSsn = childss.Child_SSN.ToString(),
                                    ChildBinId = int.Parse(rowItem.Child_BinID.ToString()),
                                    TrnDate = DateTime.Now,       // Equivalente a GETDATE()
                                    SetupId = SetupID,            // Valor de la variable SetupID
                                    Description = ""              // Se asigna cadena vacía
                                };

                                _context.PartUnitsLinkages.Add(newLinkage); // Aquí hacemos el INSERT a la DB
                                await _context.SaveChangesAsync();

                                // TODO: Update Units - Remover WIP Table Legacy
                                #region "Legacy WIP"

                                await _context.PdTblUnitsWips
                                    .Where(x => x.Ssn == (childss.Child_SSN.ToString() ?? "").ToString())
                                    .ExecuteUpdateAsync(setters => setters.SetProperty(u => u.IsActive, false));
                                #endregion

                            }
                        }
                    }

                    newModel = true;

                    return newModel;
                }
                else
                {
                    throw new InvalidOperationException("Missing one or more pcbs.");
                }
            }
            else
            {
                throw new InvalidOperationException("Empty Group");
            }

        }


