        {
            var newmodel = new UnitsCheckOutResult();

            newmodel.SSN = SSN;
            newmodel.CheckOut = false;

            if (SSN.Length == 0)
            {
                throw new ArgumentException("Select a valid SSN.");
            }

            if (mode != "SINGLE" && mode != "PANEL")
            {
                throw new ArgumentException("Please set a valid MODE: SINGLE OR PANEL.");
            }

            if (result != "FAIL" && result != "PASS")
            {
                throw new ArgumentException("Result should be PASS or FAIL");
