                var resultUpdate = await UpdateAsync(partID, IsGood, DefectCodeID, isRework, stationID, jobID, jobTypeID, jobNumber, side, SSNPanel, SSN, 0, areaID, binID, stageID, ssnQty, unitAlternate, true, ssnIndex, "", Comments, nestID, toolID_1, toolID_2, setupId, userId);

                if (resultUpdate == null)
                {
                    throw new ArgumentException("Invalid StationID");
                }
                else
                {
