                        if (record != null)
                        {
                            record.Counter = newHexValue;
                            record.UpdateDate = DateTime.Now;

                            _context.SaveChanges();
                        }


                        var dtComparasion = _context.PartOperationFunctionGetUniqueIcIds
                                                .Where(p => p.PartNo == Part_No)
                                                .Select(p => new
                                                {
                                                    p.Autoid,
                                                    p.PartNo,
                                                    p.Counter,
                                                    p.Type,
                                                    p.UpdateDate
                                                })
                                                .ToList();

                        if (dtComparasion.Count() > 0)
                        {
                            var valtempCounter = dtComparasion.FirstOrDefault().Counter.ToString();

                            if (valtempCounter == newHexValue)
                            {
                                newModel.Counter = tempCounter;
                                newModel.Type = tempTYPE;
                            }
                        }
                    }
                }
            }

            return newModel;

        }

        public async Task<List<ChildsInParent>> ArrayGetChildsAsync(string ChildOrParent, int? PartID = null, int? AreaID = null, string? Side = null, bool sortAlphabetic = false)
        {
            List<ChildsInParent> unitsInPanel = new List<ChildsInParent>();

            string PanelSSN = ChildOrParent;

            var dtParent = _context.PartUnitsArrays
                .Where(p => p.Child == ChildOrParent)
                .Select(p => p.Parente)
                .ToList();


            if (dtParent.Count() > 0)
            {
                PanelSSN = dtParent.FirstOrDefault();
            }

            // Use provided parameters or defaults
            // If PartID is -1, the LEFT JOIN will return no remapping and original order is used
            int effectivePartID = PartID ?? -1;
            int effectiveAreaID = AreaID ?? 0;
            string effectiveSide = Side ?? "A";

            // TODO: CheckIN - Valdiate SSNPnael Stage

            // Get base childs data
            var baseChilds = _context.PartUnitsArrays
                .Where(array => array.Parente == PanelSSN)
                .Select(array => new
                {
                    array.Child,
                    array.SortNo,
                    array.AutoId
                })
                .ToList();

            // Sort alphabetically/numerically BEFORE remapping if requested
            if (sortAlphabetic)
            {
                baseChilds = baseChilds
                    .OrderBy(p => p.Child, StringComparer.OrdinalIgnoreCase)
                    .Select((p, index) => new
                    {
                        p.Child,
                        SortNo = index + 1, // Reassign SortNo based on alphabetical order
                        p.AutoId
                    })
                    .ToList();
            }

            // Apply remapping logic to the (potentially) sorted childs
            var dtChilds = (from child in baseChilds
                            join remap in _context.PartOperationSerializationArrayIndexRemaps
                                on new { PartID = (int?)effectivePartID, AreaID = effectiveAreaID, Side = effectiveSide, OriginalIndex = child.SortNo }
                                equals new { PartID = (int?)remap.PartId, AreaID = remap.AreaId, Side = remap.Side, OriginalIndex = (int?)remap.OriginalIndex }
                                into remapGroup
                            from remap in remapGroup.DefaultIfEmpty()
                            select new
                            {
                                child.Child,
                                child.SortNo,
                                RemappedIndex = remap != null ? remap.RemappedIndex : child.SortNo,
                                child.AutoId
                            })
                            .OrderBy(p => p.RemappedIndex)
                            .ThenBy(p => p.AutoId)
                            .Select((p, index) => new
                            {
                                p.Child,
                                Sort_No = index + 1,
                                p.SortNo,
                                p.RemappedIndex
                            })
                            .ToList();


            if (dtChilds.Count() == 0)
            {
                throw new InvalidOperationException("No records for this unit in Parents/Arrays.");
            }
            else
            {
                foreach (var rowChild in dtChilds)
                {
                    ChildsInParent newUnit = new ChildsInParent();

                    newUnit.Parent = PanelSSN;
                    newUnit.Child = rowChild.Child.ToString();

                    newUnit.DefectCode = 0;
                    newUnit.IsGood = false;
                    newUnit.IsRework = false;

                    newUnit.IsFromPanel = true;

                    newUnit.ArrayPosition = int.Parse(rowChild.Sort_No.ToString());

                    unitsInPanel.Add(newUnit);
                }
            }

            return unitsInPanel;
        }


        public async Task<List<ChildsInParent>> ArrayGetChildsSiteAsync(string Site, string ChildOrParent)
        {
            try
            {
                // SITES AVAILABLES
                var accounts = new Dictionary<string, APIs_BeFirst.Framework.APIs.Account>
                {
                    { "JUA1", new(JUA1_APIURL, APIUser, APIPassword) },
                    { "JUA2", new(JUA2_APIURL, APIUser, APIPassword) },
                    { "GRA1", new(GRA1_APIURL, APIUser, APIPassword) },
                    { "GRP1", new(GRA1_APIURL, APIUser, APIPassword) }
                };

                // Validación de site
                if (!accounts.TryGetValue(Site.ToUpper(), out var account))
                    throw new ArgumentException($"Invalid site: {Site}");

                // Construcción de parámetros
                var parameters = new List<URLInput>
                    {
                        new() { Name = "ChildOrParent", Value = ChildOrParent }
                    }.Where(p => !string.IsNullOrEmpty(p.Value)).ToList();

                // Llamada a la API
                var response = account.API_Call("/Units/Array/GetChilds", "GET", parameters);

                // Verificación de la respuesta
                if (response.ResponseCode != 200 || string.IsNullOrWhiteSpace(response.Response))
                    throw new ApplicationException($"API call failed for site {Site}, ResponseCode: {response.ResponseCode}");

                // Deserialización segura con validación de respuesta
                var result = JsonConvert.DeserializeObject<List<ChildsInParent>>(response.Response);
                return result ?? new List<ChildsInParent>();
            }
            catch (Exception ex)
            {
                // Lanzar la excepción al controlador o manejarla
                throw new ApplicationException($"An error occurred while fetching unit history: {ex.Message}", ex);
            }
        }


        public Task<ResponseUnits> AOIGetAsync(string SSN, int AreaID, string Side)
        {

            var newModel = new ResponseUnits();


            var dtDetails = _contextProdMachines.MachinesExtractorAoiData
                                    .Where(m => m.Sn == SSN && m.AreaId == AreaID && m.Side == Side)
                                    .OrderByDescending(m => m.Trndate)
                                    .Select(m => new
                                    {
                                        m.IsGood,
                                        m.PartId,
                                    })
                                    .FirstOrDefault();


            newModel.SSN = SSN;
            newModel.Area = _context.PartOperationAreas
                                    .Where(a => a.AreaId == AreaID)
                                    .Select(a => a.Area)
                                    .FirstOrDefault();
            newModel.IsGood = false;
            newModel.Side = Side;
            newModel.PartID = 0;

            if (dtDetails != null)
            {
                newModel.IsGood = dtDetails.IsGood ?? false;
                newModel.PartID = dtDetails.PartId;
            }

            return Task.FromResult(newModel);

        }

        public async Task<UnitsCheckInResult> AOIPanelGettAsync(string SSN, int AreaID, string Side)
        {

            UnitsCheckInResult newModel = new UnitsCheckInResult();

            string SSNPANEL = SSN;

            bool allUnitsOk = true;

            var dtParente = await _context.PartUnitsArrays
                            .Where(p => p.Child == SSN || p.Parente == SSN)
                            .Select(p => p.Parente)
                            .ToListAsync();


            if (dtParente.Count() > 0)
            {
                SSNPANEL = Convert.ToString(dtParente[0]) ?? "";

                var dtChilds = _context.PartUnitsArrays
                                            .Where(p => p.Parente == SSNPANEL)
                                            .OrderBy(p => p.SortNo)
                                            .ThenBy(p => p.AutoId)
                                            .AsEnumerable()
                                            .Select((p, index) => new
                                            {
                                                p.Child,
                                                Sort_No = index + 1  // Simula ROW_NUMBER() empezando desde 1
                                            })
                                            .ToList();

                foreach (var rowChild in dtChilds)
                {
                    UnitsCheckIn newUnit = new UnitsCheckIn();
                    newUnit.SSN = Convert.ToString(rowChild.Child.ToString()) ?? "";

                    bool recordIsOK = false;

                    var resultAOI = await AOIGetAsync(newUnit.SSN, AreaID, Side);

                    if (resultAOI == null)
                    {
                        recordIsOK = false;
                        allUnitsOk = false;
                    }
                    else
                    {
                        ResponseUnits unitAOI = resultAOI;

                        if (unitAOI.IsGood)
                        {
                            recordIsOK = true;
                        }
                        else
                        {
                            recordIsOK = false;
                            allUnitsOk = false;
                        }
                    }

                    newUnit.SSNPanel = SSNPANEL;
                    newUnit.CheckIn = recordIsOK;
                    newUnit.ArrayPosition = int.Parse(rowChild.Sort_No.ToString());
                    newUnit.Message = "";
                    newModel.UnitsCheckIn.Add(newUnit);
                }

                newModel.IsPanel = true;
                newModel.CheckIn = allUnitsOk;
            }
            else
            {
                newModel.SSNPanel = SSN;
                newModel.SSNPanel = "";
                newModel.IsPanel = false;
                newModel.CheckIn = false;
                newModel.Message = "Unit not merged";
            }

            return newModel;

        }

        public async Task<ResponseUnits> GetAOIResultAsync(string SSN, int AreaID, string Side)
        {

            var newModel = new ResponseUnits();


            var dtDetails = await _contextProdMachines.MachinesExtractorAoiData
                                            .Where(m => m.Sn == SSN && m.AreaId == AreaID && m.Side == Side)
                                            .OrderByDescending(m => m.Trndate)
                                            .Select(m => new { m.IsGood, m.PartId })
                                            .FirstOrDefaultAsync();


            newModel.SSN = SSN;
            newModel.Area = await _context.PartOperationAreas
                                        .Where(a => a.AreaId == AreaID)
                                        .Select(a => a.Area)
                                        .FirstOrDefaultAsync();

            newModel.IsGood = false;
            newModel.Side = Side;
            newModel.PartID = 0;

            if (dtDetails != null)
            {
                newModel.IsGood = bool.Parse(dtDetails.IsGood.ToString());
                newModel.PartID = dtDetails.PartId;
            }

            return newModel;


        }


        //// CHECK IF THE SSN IS ON THE RABBBT LIST
        public async Task<List<Rabbits>> CheckRabbitListAsync(string SSN)
        {
            var rabbitList = await _context.QualityRabbits
                .Where(x => x.Ssn == SSN)
                .Join(_context.Parts,
                QR => QR.PartId,
                PN => PN.PartId,
                (QR, PN) => new { QR, PN })
                .Join(_context.PartOperationAreas,
                QRA => QRA.QR.AreaId,
                POA => POA.AreaId,
                (QRA, POA) => new Rabbits
                {
                    PartId = QRA.QR.PartId,
                    AreaId = QRA.QR.AreaId,
                    PartNumber = QRA.PN.PartNumber,
                    Ssn = QRA.QR.Ssn,
                    Area = POA.Area,
                    IsActive = QRA.QR.IsActive,
                    Side = QRA.QR.Side,
                    Description = QRA.QR.Description,
                    ErrorNo = QRA.QR.ErrorNo,
                    CalibrationDate = QRA.QR.CalibrationDate,
                    CalibrationExpiration = QRA.QR.CalibrationDate
                })
                .ToListAsync();

            if (rabbitList.Any())
            {
                return rabbitList;
            }
            else
            {
                throw new InvalidOperationException("The SSN isn't a rabbit.");
            }

        }

        public async Task<bool> CheckCorrectArray(string Child, int Sort_No)
        {
            var checkchild = await _context.PartUnitsArrays
                .AsNoTracking()
                .Where(x => x.Child == Child)
                .Select(x => x.Child)
                .FirstOrDefaultAsync();

            if(checkchild == null)
            {
                throw new InvalidOperationException("Child not found.");
            }

            bool result = await _context.PartUnitsArrays.AnyAsync(x => x.Child == Child && x.SortNo == Sort_No);

            return result;
        }

        // ================================================================================
        // LOCKED UNITS OPERATIONS (EF Core)
        // ================================================================================

        public async Task<List<PartUnitsLocked>> GetLockedUnitsAsync(string sn)
        {
            return await _context.PartUnitsLockeds
                .Where(x => x.Sn == sn)
                .ToListAsync();
        }

        public async Task<bool> AddLockedUnitAsync(string partNo, string sn, int controlId, string comments)
        {
            try
            {
                var lockedUnit = new PartUnitsLocked
                {
                    PartNo = partNo,
                    Sn = sn,
                    TrnDate = DateTime.Now,
                    ControlId = controlId,
                    Comments = comments,
                    Scrap = false,
                    ScrapReason = ""
                };

                await _context.PartUnitsLockeds.AddAsync(lockedUnit);
                await _context.SaveChangesAsync();
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> DeleteLockedUnitsAsync(string sn, string commentPattern)
        {
            try
            {
                var unitsToDelete = await _context.PartUnitsLockeds
                    .Where(x => x.Sn == sn && EF.Functions.Like(x.Comments, commentPattern))
                    .ToListAsync();

                if (unitsToDelete.Any())
                {
                    _context.PartUnitsLockeds.RemoveRange(unitsToDelete);
                    await _context.SaveChangesAsync();
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        // ================================================================================
        // PARENT-CHILD ARRAY OPERATIONS (EF Core)
        // ================================================================================

        public async Task<bool> AddArrayRelationshipAsync(string parent, string child, int sortNo)
        {
            try
            {
                var relationship = new PartUnitsArray
                {
                    Parente = parent,
                    Child = child,
                    TrnDate = DateTime.Now,
                    SortNo = sortNo
                };

                await _context.PartUnitsArrays.AddAsync(relationship);
                await _context.SaveChangesAsync();
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> DeleteArrayRelationshipAsync(string child)
        {
            try
            {
                var relationshipsToDelete = await _context.PartUnitsArrays
                    .Where(x => x.Child == child)
                    .ToListAsync();

                if (relationshipsToDelete.Any())
                {
                    _context.PartUnitsArrays.RemoveRange(relationshipsToDelete);
                    await _context.SaveChangesAsync();
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        public async Task<bool> CheckArrayRelationshipExistsAsync(string child)
        {
            return await _context.PartUnitsArrays.AnyAsync(x => x.Child == child);
        }
    }
}

