﻿using APIs_BeFirst.Framework.APIs;
using APIs_BeFirst.Framework.Functions;
using APIs_BeFirst.Models.DataBase;
using APIs_BeFirst.Models.Response;
using APIs_BeFirst.Service.Container;
using APIs_BeFirst.Service.Units.cs;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Data.SqlClient;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion.Internal;
using Newtonsoft.Json;
using Newtonsoft.Json.Linq;
using System.Data;
using System.Drawing;
using System.Drawing.Imaging;
using System.Runtime.Intrinsics.X86;
using System.Security.Policy;
using System.Text.RegularExpressions;
using System.Xml.Linq;
using static APIs_BeFirst.Framework.APIs.Account;
using static APIs_BeFirst.Models.Response.QualityResponse;

namespace APIs_BeFirst.Controllers
{

    //===============================================================
    // Units: APIs to get Units informations 
    //===============================================================


    [ApiController]
    [Route("[controller]")]
    public class UnitsController : ControllerBase
    {
        #region Fields
        private readonly IUnitsService _UnitsService;

        #endregion

        #region Ctor
        public UnitsController(IUnitsService unitsService)
        {
            _UnitsService = unitsService;
        }

        #endregion


        ///*=====================================
        // Check IN/Out: Save units records
        // =====================================*/

        #region "Check In/Out"

        [Authorize]
        [HttpPost("CheckIn")]
        public async Task<ActionResult<UnitsCheckInResult>> CheckIn(string SSN, int PartID, int StationID, int AreaID, string Side, int BinID, string Mode = "SINGLE", string UserId = "", DateTime? CheckIn = null)
        {

            if (Mode != "SINGLE" && Mode != "PANEL")
            {
                return BadRequest("Please set a valid MODE: SINGLE OR PANEL.");
            }

            try
            {
                var UnitsCheckInResult = await _UnitsService.CheckInAsync(SSN, PartID, StationID, AreaID, Side, BinID, Mode, UserId, CheckIn);

                return Ok(UnitsCheckInResult); // Retorna el objeto creado
            }
            catch (InvalidOperationException ex)
            {
                return BadRequest(ex.Message); // Devuelve un mensaje de error
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}"); // Error general
            }
        }

        /// <summary>
        /// This method add records for a unit.
        /// </summary>
        [Authorize]
        [HttpPost("CheckOutParametrized")]
        public async Task<ActionResult<bool>> CheckOutParametrized(string SSN, string Result, int PartID, int StationID, int AreaID, string Side, DateTime TrnDate, string NestID, string Unit_Alternate, string TestStep, string Value, string Min_Value, string Max_Value, string Nom_Value, int UnitIndex = 0)
        {
            try
            {
                var box = await _UnitsService.CheckOutParametrizedAsync(SSN, Result, PartID, StationID, AreaID, Side, TrnDate, NestID, Unit_Alternate, TestStep, Value, Min_Value, Max_Value, Nom_Value, UnitIndex);
                return Ok(box); // Retorna el objeto creado
            }
            catch (InvalidOperationException ex)
            {
                return BadRequest(ex.Message); // Devuelve un mensaje de error
            }
            catch
            {
                return BadRequest();
            }
        }

        //   /// <summary>
        //   /// This method add several records for a unit.
        //   /// </summary>
        [Authorize]
        [HttpPost("CheckOutParametrizedCollection")]
        public async Task<ActionResult<Boolean>> CheckOutParametrizedCollection(string SSN, string Result, int PartID, int StationID, int AreaID, string Side, DateTime TrnDate, string NestID, string Unit_Alternate, string testCollection, int UnitIndex = 0)
        {
            try
            {
                var box = await _UnitsService.CheckOutParametrizedCollectionAsync(SSN, Result, PartID, StationID, AreaID, Side, TrnDate, NestID, Unit_Alternate, testCollection, UnitIndex);
                return Ok(box); // Retorna el objeto creado
            }
            catch (InvalidOperationException ex)
            {
                return BadRequest(ex.Message); // Devuelve un mensaje de error
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}"); // Error general
            }
        }


        /// <summary>
        /// This method add several records for a unit.
        /// </summary>
        [Authorize]
        [HttpPost("Linkage/Add")]
        public async Task<ActionResult<bool>> LinkageAdd(int PartID, string GroupName, string SSN, string ChildCollection)
        {
            try
            {
                var result = await _UnitsService.LinkageAddAsync(PartID, GroupName, SSN, ChildCollection);

                return Ok(result);
            }
            catch (ArgumentException argEx)
            {
                // Errores de validación
                return BadRequest(argEx.Message);
            }
            catch (InvalidOperationException argEx)
