import os
import subprocess
import ctypes
import psutil
import time

# Set the path where the .reg files are stored
REG_FOLDER = r"D:\0 - Apps\LCX\4 - Repos\env_config"

def import_reg_file(site):
    """Import the registry file using reg import (compatible with IronPython)."""
    reg_file = os.path.join(REG_FOLDER, f"{site}.reg")

    if not os.path.exists(reg_file):
        print(f"Error: The file {reg_file} does not exist.")
        return False

    try:
        # Use cmd.exe to run the reg import command
        command = f'cmd.exe /c reg import "{reg_file}"'
        subprocess.call(command, shell=True)
        print(f"Successfully imported {reg_file}")
        return True
    except Exception as e:
        print(f"Error importing {reg_file}: {e}")
        return False

def get_visual_studio_processes():
    """Detect running Visual Studio instances."""
    vs_processes = []
    vs_names = ["devenv.exe", "msbuild.exe"]

    for proc in psutil.process_iter(['pid', 'name', 'exe']):
        try:
            if proc.info['name'] and proc.info['name'].lower() in vs_names:
                vs_processes.append(proc)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

    return vs_processes

def restart_visual_studio():
    """Restart Visual Studio instances."""
    vs_processes = get_visual_studio_processes()

    if not vs_processes:
        print("No Visual Studio instances detected.")
        return

    print(f"\nDetected {len(vs_processes)} Visual Studio process(es) running:")
    for proc in vs_processes:
        try:
            print(f"  - {proc.info['name']} (PID: {proc.info['pid']})")
        except:
            pass

    restart = input("\nRestart Visual Studio to apply changes? (y/n): ").strip().lower()

    if restart == 'y':
        # Save VS executable paths before terminating
        vs_exes = []
        for proc in vs_processes:
            try:
                if proc.info['exe'] and 'devenv.exe' in proc.info['name'].lower():
                    vs_exes.append(proc.info['exe'])
            except:
                pass

        # Terminate all VS processes
        print("\nClosing Visual Studio instances...")
        for proc in vs_processes:
            try:
                proc.terminate()
            except:
                pass

        # Wait for processes to close
        gone, alive = psutil.wait_procs(vs_processes, timeout=10)

        # Force kill if still alive
        for proc in alive:
            try:
                proc.kill()
            except:
                pass

        time.sleep(2)

        # Restart Visual Studio instances
        if vs_exes:
            print("Restarting Visual Studio...")
            for exe in set(vs_exes):  # Remove duplicates
                try:
                    subprocess.Popen([exe])
                    print(f"  Started: {exe}")
                except Exception as e:
                    print(f"  Error starting {exe}: {e}")

        print("\nVisual Studio restarted with updated environment variables.")
    else:
        print("\nSkipping restart. You'll need to manually restart Visual Studio to apply changes.")

def main():
    print("Available Sites:")
    sites = [f.split(".reg")[0] for f in os.listdir(REG_FOLDER) if f.endswith(".reg")]

    if not sites:
        print("No .reg files found.")
        return

    for idx, site in enumerate(sites, 1):
        print(f"{idx}. {site}")

    choice = input("Select a site (enter number or name): ").strip()

    if choice.isdigit():
        choice = int(choice)
        if 1 <= choice <= len(sites):
            site = sites[choice - 1]
        else:
            print("Invalid selection.")
            return
    else:
        site = choice

    if site in sites:
        success = import_reg_file(site)
        if success:
            refresh_environment()
            restart_visual_studio()
    else:
        print("Invalid site name.")

def refresh_environment():
    """Broadcast environment variable changes to running applications."""
    try:
        HWND_BROADCAST = 0xFFFF
        WM_SETTINGCHANGE = 0x1A
        SMTO_ABORTIFHUNG = 0x0002

        # Use SendMessageTimeout for more reliable broadcasting
        result = ctypes.c_long()
        ctypes.windll.user32.SendMessageTimeoutW(
            HWND_BROADCAST,
            WM_SETTINGCHANGE,
            0,
            "Environment",
            SMTO_ABORTIFHUNG,
            5000,  # 5 second timeout
            ctypes.byref(result)
        )
        print("Environment variables broadcast to running applications.")
    except Exception as e:
        print(f"Error refreshing environment variables: {e}")

